import{_ as a,o as i,c as s,ao as t}from"./chunks/framework.B9--V88m.js";const p=JSON.parse('{"title":"Julia Runtime and Shared Libraries","description":"","frontmatter":{},"headers":[],"relativePath":"guide/runtime.md","filePath":"guide/runtime.md","lastUpdated":1781453740000}'),n={name:"guide/runtime.md"};function o(l,e,r,d,c,h){return i(),s("div",null,[...e[0]||(e[0]=[t(`<h1 id="Julia-Runtime-and-Shared-Libraries" tabindex="-1">Julia Runtime and Shared Libraries <a class="header-anchor" href="#Julia-Runtime-and-Shared-Libraries" aria-label="Permalink to &quot;Julia Runtime and Shared Libraries {#Julia-Runtime-and-Shared-Libraries}&quot;">​</a></h1><h2 id="How-the-runtime-is-bundled" tabindex="-1">How the runtime is bundled <a class="header-anchor" href="#How-the-runtime-is-bundled" aria-label="Permalink to &quot;How the runtime is bundled {#How-the-runtime-is-bundled}&quot;">​</a></h2><p>When <code>build_mex</code> is called with <code>bundle=true</code> (the default), <code>juliac --bundle</code> copies <code>libjulia.so</code> and all required Julia artifacts into the output directory alongside the MEX file. This makes the bundle self-contained — no Julia installation is needed on the end-user&#39;s machine.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>mex/</span></span>
<span class="line"><span>├── myfunction.mexa64</span></span>
<span class="line"><span>├── libjulia.so              ← shared by all MEX files</span></span>
<span class="line"><span>├── libjulia-internal.so</span></span>
<span class="line"><span>├── libopenlibm.so</span></span>
<span class="line"><span>├── sys.so                   ← trimmed system image</span></span>
<span class="line"><span>└── mexicah_setup.m</span></span></code></pre></div><h2 id="Sharing-the-runtime-across-multiple-MEX-files" tabindex="-1">Sharing the runtime across multiple MEX files <a class="header-anchor" href="#Sharing-the-runtime-across-multiple-MEX-files" aria-label="Permalink to &quot;Sharing the runtime across multiple MEX files {#Sharing-the-runtime-across-multiple-MEX-files}&quot;">​</a></h2><p>When MATLAB loads a MEX file with <code>dlopen</code>, the OS dynamic linker maps <code>libjulia.so</code> by its soname. If another MEX file requests the same soname, the linker reuses the already-mapped copy — the runtime lives in memory exactly once per MATLAB session, no matter how many MEX files are loaded.</p><p>This means:</p><ul><li><p>Memory footprint does not grow linearly with the number of MEX files.</p></li><li><p>GC runs are shared across all MEX files (one GC, no fragmentation).</p></li></ul><h2 id="The-mexicah_setup.m-file" tabindex="-1">The <code>mexicah_setup.m</code> file <a class="header-anchor" href="#The-mexicah_setup.m-file" aria-label="Permalink to &quot;The \`mexicah_setup.m\` file {#The-mexicah_setup.m-file}&quot;">​</a></h2><p>Before calling any MEX function for the first time, the MATLAB user must run:</p><div class="language-matlab vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">matlab</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">run(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;path/to/mex/mexicah_setup.m&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><p>This prepends the bundle directory to <code>LD_LIBRARY_PATH</code> (Linux) or <code>DYLD_LIBRARY_PATH</code> (macOS) so MATLAB can resolve <code>libjulia.so</code> when it loads the MEX file with <code>dlopen</code>.</p><p>Add this call to your MATLAB project&#39;s startup script to make it transparent.</p><h2 id="Windows" tabindex="-1">Windows <a class="header-anchor" href="#Windows" aria-label="Permalink to &quot;Windows {#Windows}&quot;">​</a></h2><p>On Windows (<code>mexw64</code>) the runtime DLLs must be on the system <code>PATH</code> or in the same directory as the MEX file. <code>mexicah_setup.m</code> adds the bundle directory to <code>PATH</code> accordingly. Windows support is a Phase 2 feature.</p><h2 id="Initialization-guard" tabindex="-1">Initialization guard <a class="header-anchor" href="#Initialization-guard" aria-label="Permalink to &quot;Initialization guard {#Initialization-guard}&quot;">​</a></h2><p>Each MEX file calls <code>_mexicah_init_once()</code> at the top of <code>mexFunction</code>. This function uses a <code>Threads.Atomic{Int}</code> compare-and-swap to ensure that any per-session setup code runs exactly once, even if MATLAB calls the MEX function concurrently from multiple threads.</p>`,17)])])}const m=a(n,[["render",o]]);export{p as __pageData,m as default};
